import React, { useState } from 'react';
import './AIContentGenerator.css'; // 이 CSS 파일도 새로 만드셔야 합니다!

const AIContentGenerator = ({ apiKey, selectedLanguage, onCategoriesGenerated }) => {
  const [isLoading, setIsLoading] = useState(false);
  const [difficultyLevel, setDifficultyLevel] = useState('beginner');
  const [error, setError] = useState('');
  const [generatedContent, setGeneratedContent] = useState(null);

  // 언어별 레벨 설명
  const levelDescriptions = {
    beginner: {
      english: "Simple daily conversations with basic vocabulary",
      japanese: "基本的な語彙を使った簡単な日常会話",
      korean: "기본 어휘를 사용한 간단한 일상 대화",
      chinese: "使用基本词汇的简单日常对话",
      spanish: "Conversaciones diarias simples con vocabulario básico",
      french: "Conversations quotidiennes simples avec un vocabulaire de base",
      german: "Einfache Alltagsgespräche mit grundlegendem Vokabular",
      russian: "Простые ежедневные разговоры с базовой лексикой",
      arabic: "محادثات يومية بسيطة مع مفردات أساسية",
      vietnamese: "Hội thoại hàng ngày đơn giản với từ vựng cơ bản",
      thai: "การสนทนาประจำวันง่ายๆ ด้วยคำศัพท์พื้นฐาน",
      indonesian: "Percakapan sehari-hari sederhana dengan kosakata dasar"
    },
    intermediate: {
      english: "Complex scenarios with varied vocabulary and grammar",
      japanese: "多様な語彙と文法を使用した複雑なシナリオ",
      korean: "다양한 어휘와 문법을 사용한 복잡한 시나리오",
      chinese: "使用多样词汇和语法的复杂场景",
      spanish: "Escenarios complejos con vocabulario y gramática variados",
      french: "Scénarios complexes avec vocabulaire et grammaire variés",
      german: "Komplexe Szenarien mit vielfältigem Vokabular und Grammatik",
      russian: "Сложные сценарии с разнообразным словарным запасом и грамматикой",
      arabic: "سيناريوهات معقدة مع مفردات وقواعد نحوية متنوعة",
      vietnamese: "Các tình huống phức tạp với từ vựng và ngữ pháp đa dạng",
      thai: "สถานการณ์ที่ซับซ้อนด้วยคำศัพท์และไวยากรณ์ที่หลากหลาย",
      indonesian: "Skenario kompleks dengan kosakata dan tata bahasa yang bervariasi"
    },
    advanced: {
      english: "Sophisticated discussions on abstract topics with nuanced expressions",
      japanese: "ニュアンスのある表現を使った抽象的なトピックに関する洗練された議論",
      korean: "미묘한 표현을 사용한 추상적인 주제에 대한 세련된 토론",
      chinese: "使用细微表达的抽象主题的复杂讨论",
      spanish: "Discusiones sofisticadas sobre temas abstractos con expresiones matizadas",
      french: "Discussions sophistiquées sur des sujets abstraits avec des expressions nuancées",
      german: "Anspruchsvolle Diskussionen über abstrakte Themen mit nuancierten Ausdrücken",
      russian: "Сложные обсуждения абстрактных тем с нюансированными выражениями",
      arabic: "مناقشات متطورة حول مواضيع مجردة مع تعبيرات دقيقة",
      vietnamese: "Thảo luận phức tạp về các chủ đề trừu tượng với các biểu hiện tinh tế",
      thai: "การสนทนาที่ซับซ้อนเกี่ยวกับหัวข้อนามธรรมด้วยการแสดงออกที่มีความละเอียดอ่อน",
      indonesian: "Diskusi canggih tentang topik abstrak dengan ekspresi bernuansa"
    }
  };

  // AI 콘텐츠 생성 함수
  const generateAIContent = async () => {
    if (!apiKey) {
      setError('API 키를 먼저 입력해주세요.');
      return;
    }

    setIsLoading(true);
    setError('');

    try {
      // 언어에 맞게 난이도 설명 가져오기
      const languageName = getLanguageName(selectedLanguage);
      const levelDesc = levelDescriptions[difficultyLevel][selectedLanguage] || levelDescriptions[difficultyLevel].english;

      // OpenAI API 요청을 위한 프롬프트 구성
      const prompt = `
너는 글로벌 어학 학습 플랫폼에 적용될 AI 콘텐츠 생성기야.
사용자의 언어 수준(${difficultyLevel})에 따라 다음과 같이 동작해줘:

1. ${languageName} 학습을 위한 새로운 카테고리 9개를 만들어줘. 단, 다음 주제는 제외: 정치, 종교, 북한, 성인물, 논쟁적 이슈
2. 카테고리당 학습 질문은 3개씩 생성하되, 순차적 흐름이 있도록 구성해줘.
3. 모든 질문은 "${levelDesc}" 수준에 맞게 난이도를 유지해야 해.
4. 카테고리는 일상 생활에서 자주 사용되는 실용적인 주제로 구성해줘.

출력은 다음 JSON 형식으로 제공해줘:
{
  "categories": [
    {
      "id": "unique_id_1",
      "name": "카테고리명",
      "icon": "이모지",
      "questions": ["질문1", "질문2", "질문3"]
    },
    ...
  ]
}

이모지는 카테고리의 특성을 잘 나타내는 것으로 선택해줘.
모든 콘텐츠는 ${languageName}로 작성해줘.
      `;

      // OpenAI API 호출
      const response = await fetch('https://api.openai.com/v1/chat/completions', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${apiKey}`
        },
        body: JSON.stringify({
          model: 'gpt-4-turbo',
          messages: [
            { role: 'system', content: '당신은 언어 학습 콘텐츠 전문가입니다.' },
            { role: 'user', content: prompt }
          ],
          temperature: 0.7
        })
      });

      if (!response.ok) {
        throw new Error(`API 요청 실패: ${response.status}`);
      }

      const data = await response.json();
      const generatedContentString = data.choices[0].message.content;
      
      // JSON 문자열에서 실제 JSON 객체만 추출 (텍스트가 포함되어 있을 수 있음)
      const jsonMatch = generatedContentString.match(/{[\s\S]*}/);
      if (!jsonMatch) {
        throw new Error('응답에서 JSON 형식을 찾을 수 없습니다.');
      }
      
      const contentJson = JSON.parse(jsonMatch[0]);
      setGeneratedContent(contentJson);
      
      // 부모 컴포넌트에 생성된 카테고리 전달
      if (onCategoriesGenerated && contentJson.categories) {
        onCategoriesGenerated(contentJson.categories);
      }

    } catch (error) {
      console.error('AI 콘텐츠 생성 오류:', error);
      setError(`콘텐츠 생성 중 오류가 발생했습니다: ${error.message}`);
    } finally {
      setIsLoading(false);
    }
  };

  // 언어 이름 가져오기 함수
  const getLanguageName = (languageCode) => {
    const languageMap = {
      'english': 'English',
      'japanese': '日本語',
      'korean': '한국어',
      'chinese': '中文',
      'spanish': 'Español',
      'french': 'Français',
      'german': 'Deutsch',
      'russian': 'Русский',
      'arabic': 'العربية',
      'vietnamese': 'Tiếng Việt',
      'thai': 'ไทย',
      'indonesian': 'Bahasa Indonesia'
    };
    return languageMap[languageCode] || 'English';
  };

  return (
    <div className="ai-generator-container">
      <h2 className="generator-title">AI Learning Content Generator</h2>
      <p className="generator-description">
      Choose your learning level and click the button to generate a new learning category and set of questions using AI.
      </p>
      
      <div className="generator-controls">
        <div className="difficulty-selector">
          <label>Difficulty Level:</label>
          <div className="difficulty-buttons">
            <button 
              className={`difficulty-button ${difficultyLevel === 'beginner' ? 'active' : ''}`}
              onClick={() => setDifficultyLevel('beginner')}
            >
              Beginner
            </button>
            <button 
              className={`difficulty-button ${difficultyLevel === 'intermediate' ? 'active' : ''}`}
              onClick={() => setDifficultyLevel('intermediate')}
            >
              Intermediate
            </button>
            <button 
              className={`difficulty-button ${difficultyLevel === 'advanced' ? 'active' : ''}`}
              onClick={() => setDifficultyLevel('advanced')}
            >
              Advanced
            </button>
          </div>
        </div>
        
        <button 
          className="generate-button"
          onClick={generateAIContent}
          disabled={isLoading || !apiKey}
        >
          {isLoading ? (
            <>
              <span className="loading-spinner"></span>
              Generating AI Content...
            </>
          ) : 'Add New Category'}
        </button>
      </div>
      
      {error && <div className="error-message">{error}</div>}
      
      {generatedContent && (
        <div className="preview-container">
          <h3>Generated Category Preview</h3>
          <div className="categories-preview">
            {generatedContent.categories.map((category, index) => (
              <div key={index} className="category-preview-card">
                <div className="category-icon">{category.icon}</div>
                <h4>{category.name}</h4>
                <div className="question-count">
                  {category.questions.length}개 질문
                </div>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

export default AIContentGenerator;