// GitHubQuizShare.js
import React, { useState } from 'react';
import './GitHubQuizShare.css';
import { saveQuizToGitHub, createShareURL } from './GitHubService';

const GitHubQuizShare = ({ quizData, language, category, level, onSuccess, onError, onClose }) => {
  const [isSharing, setIsSharing] = useState(false);
  const [shareStatus, setShareStatus] = useState('');
  const [shareUrl, setShareUrl] = useState('');
  
  const handleShare = async () => {
    setIsSharing(true);
    setShareStatus('퀴즈 데이터를 GitHub에 저장하는 중...');
    
    try {
      // 퀴즈 데이터를 GitHub에 저장
      const quizMeta = await saveQuizToGitHub(quizData, language, category, level);
      
      // 공유 URL 생성
      const url = createShareURL(quizMeta);
      setShareUrl(url);
      
      setShareStatus('✅ 퀴즈가 성공적으로 저장되었습니다!');
      
      if (onSuccess) {
        onSuccess(quizMeta);
      }
    } catch (error) {
      console.error('퀴즈 공유 오류:', error);
      setShareStatus(`❌ 오류: ${error.message}`);
      
      if (onError) {
        onError(error);
      }
    } finally {
      setIsSharing(false);
    }
  };
  
 const handleCopyUrl = () => {
    navigator.clipboard.writeText(shareUrl)
      .then(() => {
        alert('URL이 클립보드에 복사되었습니다.');
      })
      .catch(err => {
        console.error('URL 복사 오류:', err);
        alert('URL 복사에 실패했습니다. 수동으로 복사해주세요.');
      });
  };
  
  return (
    <div className="github-share-container">
      <h2>퀴즈 공유하기</h2>
      
      <div className="quiz-info">
        <p>
          <strong>언어:</strong> {language} | 
          <strong>카테고리:</strong> {category} | 
          <strong>난이도:</strong> {level}
        </p>
      </div>
      
      {!shareUrl ? (
        <>
          <div className="share-actions">
            <button 
              onClick={handleShare} 
              className="share-button"
              disabled={isSharing}
            >
              {isSharing ? '저장 중...' : 'GitHub에 저장 및 공유'}
            </button>
            <button onClick={onClose} className="cancel-button">
              취소
            </button>
          </div>
          
          {shareStatus && (
            <div className={`share-status ${
              shareStatus.includes('✅') ? 'success' : 
              shareStatus.includes('❌') ? 'error' : 'info'
            }`}>
              {shareStatus}
            </div>
          )}
        </>
      ) : (
        <div className="share-success">
          <p>아래 URL을 통해 이 퀴즈를 공유할 수 있습니다:</p>
          <div className="share-url-container">
            <input 
              type="text" 
              value={shareUrl} 
              readOnly 
              className="share-url"
              onClick={(e) => e.target.select()}
            />
            <button onClick={handleCopyUrl} className="copy-button">
              복사
            </button>
          </div>
          <div className="share-complete-actions">
            <button onClick={onClose} className="close-button">
              닫기
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default GitHubQuizShare;