// 피드백 옵션 변경 함수
const handleFeedbackOptionChange = (option) => {
  if (option === 'correct') {
    setFeedbackOptions({
      ...feedbackOptions,
      showCorrectOnly: !feedbackOptions.showCorrectOnly,
      showIncorrectOnly: false // 상호 배타적으로 처리
    });
  } else if (option === 'incorrect') {
    setFeedbackOptions({
      ...feedbackOptions,
      showIncorrectOnly: !feedbackOptions.showIncorrectOnly,
      showCorrectOnly: false // 상호 배타적으로 처리
    });
  }
};

