  let csvContent = "번호,문제,정답,사용자답변,해설\n";

  // 각 문제의 데이터를 CSV 행으로 추가
  quizData.quiz.forEach((question, index) => {
    const userAnswer = userAnswers[index] ? 
      (typeof userAnswers[index] === 'object' ? 
        userAnswers[index].text || userAnswers[index].id : 
        userAnswers[index]) : 
      '답변 없음';

    // 특수문자 처리 (쉼표, 줄바꿈 등)
    const sanitizedQuestion = `"${question.question.replace(/"/g, '""')}"`;
    const sanitizedAnswer = `"${question.answer.replace(/"/g, '""')}"`;
    const sanitizedUserAnswer = `"${String(userAnswer).replace(/"/g, '""')}"`;
    const sanitizedExplanation = `"${question.explanation.replace(/"/g, '""')}"`;

    // CSV 행 추가
    csvContent += `${index + 1},${sanitizedQuestion},${sanitizedAnswer},${sanitizedUserAnswer},${sanitizedExplanation}\n`;
  });

  // CSV 파일 만들기
  const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
  const url = URL.createObjectURL(blob);

  // 현재 날짜를 파일명에 포함
  const date = new Date().toISOString().slice(0, 10);
