// HTML 리포트 다운로드 함수
export const downloadHtmlReport = (htmlReport, testType, mockTestData) => {
  if (!htmlReport) {
    alert('No report available to download.');
    return;
  }

  // HTML Blob 생성
  const blob = new Blob([htmlReport], { type: 'text/html' });
  const url = URL.createObjectURL(blob);

  // 다운로드 링크 생성
  const link = document.createElement('a');
  link.href = url;
  link.download = `OpenVoiceAI_${mockTestData[testType].name}_Report_${new Date().toISOString().split('T')[0]}.html`;
  document.body.appendChild(link);
  link.click();

  // 리소스 정리
  setTimeout(() => {
    URL.revokeObjectURL(url);
    document.body.removeChild(link);
  }, 100);
};

export default {
  generateSampleResponse,
  generateResponseFeedback,
  generateSummaryReport,
  downloadHtmlReport,
  extractFeedbackSection
};