// GitHubQuizLoader.js
import React, { useState, useEffect } from 'react';
import './GitHubQuizLoader.css';
import { searchQuizzes, loadQuizFromGitHub } from './GitHubService';

const GitHubQuizLoader = ({ selectedLanguage, onQuizLoad, onClose }) => {
  const [searchParams, setSearchParams] = useState({
    language: selectedLanguage,
    category: '',
    level: '',
    keyword: ''
  });
  
  const [searchResults, setSearchResults] = useState([]);
  const [isLoading, setIsLoading] = useState(false);
  const [loadingStatus, setLoadingStatus] = useState('');
  const [selectedQuiz, setSelectedQuiz] = useState(null);
  
  // 초기 검색 실행
  useEffect(() => {
    performSearch();
  }, [selectedLanguage]);
  
  // 검색 파라미터 변경 처리
  const handleSearchChange = (field, value) => {
    setSearchParams(prev => ({
      ...prev,
      [field]: value
    }));
  };
  
  // 검색 실행
  const performSearch = async () => {
    setIsLoading(true);
    setLoadingStatus('퀴즈를 검색하는 중...');
    
    try {
      const results = await searchQuizzes(searchParams);
      setSearchResults(results);
      
      if (results.length === 0) {
        setLoadingStatus('검색 결과가 없습니다. 다른 조건으로 검색해 보세요.');
      } else {
        setLoadingStatus('');
      }
    } catch (error) {
      console.error('퀴즈 검색 오류:', error);
      setLoadingStatus(`❌ 검색 오류: ${error.message}`);
      setSearchResults([]);
    } finally {
      setIsLoading(false);
    }
  };
  
  // 퀴즈 로드
  const loadQuiz = async (quizMeta) => {
    setSelectedQuiz(quizMeta);
    setIsLoading(true);
    setLoadingStatus(`"${quizMeta.category}" 퀴즈를 불러오는 중...`);
    
    try {
      const quizData = await loadQuizFromGitHub(quizMeta.path);
      
      if (!quizData) {
        throw new Error('퀴즈 데이터를 불러올 수 없습니다.');
      }
      
      setLoadingStatus('✅ 퀴즈 불러오기 성공!');
      
      // 부모 컴포넌트에 로드된 퀴즈 전달
      if (onQuizLoad) {
        onQuizLoad(quizData, quizMeta);
      }
      
      // 로드 성공 시 모달 닫기
      setTimeout(() => {
        onClose();
      }, 1000);
      
    } catch (error) {
      console.error('퀴즈 로드 오류:', error);
      setLoadingStatus(`❌ 퀴즈 로드 오류: ${error.message}`);
    } finally {
      setIsLoading(false);
    }
  };
  
  // 검색 제출
  const handleSubmit = (e) => {
    e.preventDefault();
    performSearch();
  };
  
  return (
    <div className="github-loader-container">
      <h2>저장된 퀴즈 불러오기</h2>
      
      <form onSubmit={handleSubmit} className="search-form">
        <div className="search-controls">
          <div className="search-field">
            <label>언어</label>
            <select 
              value={searchParams.language}
              onChange={(e) => handleSearchChange('language', e.target.value)}
            >
              <option value="">모든 언어</option>
              <option value="english">English</option>
              <option value="korean">한국어</option>
              <option value="japanese">日本語</option>
              <option value="chinese">中文</option>
              <option value="spanish">Español</option>
              <option value="french">Français</option>
              <option value="german">Deutsch</option>
              <option value="russian">Русский</option>
              <option value="arabic">العربية</option>
              <option value="vietnamese">Tiếng Việt</option>
              <option value="thai">ไทย</option>
              <option value="indonesian">Bahasa Indonesia</option>
            </select>
          </div>
          
          <div className="search-field">
            <label>난이도</label>
            <select 
              value={searchParams.level}
              onChange={(e) => handleSearchChange('level', e.target.value)}
            >
              <option value="">모든 난이도</option>
              <option value="beginner">초급</option>
              <option value="intermediate">중급</option>
              <option value="advanced">고급</option>
            </select>
          </div>
          
          <div className="search-field">
            <label>키워드</label>
            <input 
              type="text"
              value={searchParams.keyword}
              onChange={(e) => handleSearchChange('keyword', e.target.value)}
              placeholder="카테고리 또는 키워드"
            />
          </div>
          
          <button type="submit" className="search-button" disabled={isLoading}>
            {isLoading ? '검색 중...' : '검색'}
          </button>
        </div>
      </form>
      
      {loadingStatus && (
        <div className={`loading-status ${
          loadingStatus.includes('✅') ? 'success' : 
          loadingStatus.includes('❌') ? 'error' : 'info'
        }`}>
          {loadingStatus}
        </div>
      )}
      
      <div className="search-results">
        {searchResults.length > 0 ? (
          <div className="result-list">
            {searchResults.map((quiz, index) => (
              <div 
                key={quiz.id || index}
                className={`result-item ${selectedQuiz && selectedQuiz.id === quiz.id ? 'selected' : ''}`}
                onClick={() => loadQuiz(quiz)}
              >
                <div className="result-language">{quiz.language}</div>
                <div className="result-content">
                  <h3>{quiz.category}</h3>
                  <div className="result-meta">
                    <span className={`result-level ${quiz.level}`}>
                      {quiz.level === 'beginner' ? '초급' : 
                       quiz.level === 'intermediate' ? '중급' : '고급'}
                    </span>
                    <span className="result-date">
                      {new Date(quiz.createdAt).toLocaleDateString()}
                    </span>
                  </div>
                </div>
              </div>
            ))}
          </div>
        ) : (
          !isLoading && <div className="no-results">검색 결과가 없습니다</div>
        )}
      </div>
      
      <div className="loader-actions">
        <button onClick={onClose} className="cancel-button">
          닫기
        </button>
      </div>
    </div>
  );
};

export default GitHubQuizLoader;