  // ===== RECORDING & RECOGNITION FUNCTIONS =====
  // 녹음 시작 (안드로이드 호환성 개선됨)
  const startRecording = async () => {
    try {
      // 이미 녹음 중이면 중지
      if (isRecording) {
        stopRecording();
      }
      
      setAudioUrl('');
      setAudioBlob(null);
      setTranscript('');
      setFeedback('');
      setModelAnswer('');
    
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      mediaRecorderRef.current = new MediaRecorder(stream);
      audioChunksRef.current = [];

      // 이전 인식기 정리
      if (recognitionRef.current) {
        try {
          recognitionRef.current.stop();
        } catch (e) {
          console.log('인식기 정리 중 오류 (무시 가능)', e);
        }
        
        recognitionRef.current.onresult = null;
        recognitionRef.current.onend = null;
        recognitionRef.current.onerror = null;
      }

      // 새 인식기 설정 - AudioRecognition.js의 createSpeechRecognition 사용
      recognitionRef.current = createSpeechRecognition(
        languageData[selectedLanguage]?.code || 'en-US',
        (newTranscript) => setTranscript(newTranscript),
        setIsRecording
      );
      
      // 음성 인식 시작
      try {
        recognitionRef.current.start();
      } catch (error) {
        console.error('음성 인식 시작 오류:', error);
        alert("음성 인식을 시작할 수 없습니다. 브라우저를 새로고침하고 다시 시도해보세요.");
      }

      // 미디어 레코더 설정
      mediaRecorderRef.current.ondataavailable = (event) => {
        if (event.data.size > 0) {
          audioChunksRef.current.push(event.data);
        }
      };

      mediaRecorderRef.current.onstop = () => {
        const audioBlob = new Blob(audioChunksRef.current, { type: 'audio/webm' });
        setAudioBlob(audioBlob);
        const audioUrl = URL.createObjectURL(audioBlob);
        setAudioUrl(audioUrl);
      };

      // 레코더 시작
      mediaRecorderRef.current.start(100);
      setIsRecording(true);
    } catch (err) {
      console.error("Recording error:", err);
      alert("마이크에 접근할 수 없습니다. 마이크 권한을 확인해주세요.");
    }
  };
  
  // 녹음 중지
  const stopRecording = () => {
    // 미디어 레코더 중지
    if (mediaRecorderRef.current && mediaRecorderRef.current.state === 'recording') {
      mediaRecorderRef.current.stop();
      
      if (mediaRecorderRef.current.stream) {
        mediaRecorderRef.current.stream.getTracks().forEach(track => track.stop());
      }
    }
    
    // 음성 인식 중지
    if (recognitionRef.current) {
      try {
        recognitionRef.current.stop();
      } catch (error) {
        console.error('음성 인식 중지 오류:', error);
      }
    }
    
    setIsRecording(false);
  };
  
  // ===== SPEECH SYNTHESIS FUNCTIONS =====
  // 언어 및 설정에 기반한 최적 음성 선택
  const getEnhancedVoice = useCallback(() => {
    // 사용 가능한 음성 또는 비어 있는 경우 다시 가져오기
    const voices = availableVoices.length > 0 ? 
      availableVoices : 
      window.speechSynthesis.getVoices();
    
    let voicePool = [];
    const currentLang = languageData?.[selectedLanguage]?.code || 'en-US';
    
    // 음성 유형 및 성별로 필터링
    if (selectedVoiceType === 'adult') {
      if (selectedVoiceGender === 'female') {
        voicePool = voices.filter(v => 
          v.lang.includes(currentLang) && 
          (v.name.includes('Female') || v.name.includes('female') || v.name.toLowerCase().includes('woman'))
        );
      } else {
        voicePool = voices.filter(v => 
          v.lang.includes(currentLang) && 
          (v.name.includes('Male') || v.name.includes('male') || v.name.toLowerCase().includes('man'))
        );
      }
    } else { // 아동 음성
      // 아동 음성은 덜 일반적이므로 명칭 패턴 사용
      if (selectedVoiceGender === 'female') {
        voicePool = voices.filter(v => 
          v.lang.includes(currentLang) && 
          (v.name.includes('Kid') || v.name.includes('Child') || v.name.includes('Young'))
        );
        // 아동 음성이 없으면 성인 여성 음성으로 대체
        if (voicePool.length === 0) {
          voicePool = voices.filter(v => 
            v.lang.includes(currentLang) && 
            (v.name.includes('Female') || v.name.includes('female'))
          );
        }
      } else {
        voicePool = voices.filter(v => 
          v.lang.includes(currentLang) && 
          (v.name.includes('Boy') || v.name.includes('Kid') || v.name.includes('Child'))
        );
        // 아동 음성이 없으면 성인 남성 음성으로 대체
        if (voicePool.length === 0) {
          voicePool = voices.filter(v => 
            v.lang.includes(currentLang) && 
            (v.name.includes('Male') || v.name.includes('male'))
          );
        }
      }
    }
    
    // 유형/성별 일치가 없으면 언어만 일치하도록 대체
    if (voicePool.length === 0) {
      voicePool = voices.filter(v => v.lang.includes(currentLang));
    }
    
    // 최종 대체 음성
    return voicePool.length > 0 ? voicePool[0] : voices[0];
  }, [availableVoices, selectedLanguage, selectedVoiceGender, selectedVoiceType]);
  
  // 고급 고품질 음성 합성
  const speakWithEnhancedVoice = useCallback((text, rate = questionPlaybackRate, isChat = false) => {
    // 진행 중인 음성 취소
    if (window.speechSynthesis.speaking) {
      window.speechSynthesis.cancel();
    }
    
    // 채팅 모드일 경우 AI 말하기 상태 설정
    if (isChat) {
      setIsAiSpeaking(true);
    }
    
    // 현재 언어 확인
    const currentLanguage = isChat ? chatLanguage : selectedLanguage;
    const currentLangCode = languageData[currentLanguage]?.code || 'en-US';
    
    console.log("현재 언어:", currentLanguage, "언어 코드:", currentLangCode);
    console.log("텍스트:", text);
    
    // 모든 언어에 대해 전체 문장을 한 번에 처리
    const utterance = new SpeechSynthesisUtterance(text);
    
    // 언어 설정
    utterance.lang = currentLangCode;
    utterance.rate = rate;
    utterance.pitch = selectedVoiceType === 'child' ? 1.2 : 1.0;
    utterance.volume = 1.0;
    
    // 적절한 음성 선택
    const enhancedVoice = getEnhancedVoice();
    if (enhancedVoice) {
      utterance.voice = enhancedVoice;
      console.log("선택된 음성:", enhancedVoice.name, enhancedVoice.lang);
    }
    
    // 종료 이벤트 처리
    utterance.onend = () => {
      if (isChat) {
        setIsAiSpeaking(false);
      }
      console.log("음성 재생 완료");
    };
    
    // 오류 처리
    utterance.onerror = (error) => {
      console.error("음성 합성 오류:", error);
      if (isChat) {
        setIsAiSpeaking(false);
      }
    };
    
    // 디버깅용 로그
    utterance.onstart = () => console.log("음성 재생 시작");
    
    // 음성 합성 실행
    window.speechSynthesis.speak(utterance);
    
  }, [audioQuality, getEnhancedVoice, questionPlaybackRate, selectedVoiceType, chatLanguage, selectedLanguage]);
  
  // 질문 재생
  const speakQuestion = useCallback((text) => {
    speakWithEnhancedVoice(text);
  }, [speakWithEnhancedVoice]);
  
  // 음성 중지
  const stopSpeech = useCallback(() => {
    window.speechSynthesis.cancel();
    setIsAiSpeaking(false);
  }, []);
  
  // 질문에서 키워드 강조
  const highlightKeywords = useCallback((text) => {
    if (!text) return '';
  
    // 단어 경계로 분할하고 멀티바이트 문자 처리
    const words = text.split(/\b|(?=[\u3040-\u30ff\u3400-\u4dbf\u4e00-\u9fff\u0600-\u06FF\uAC00-\uD7A3])|(?<=[\u3040-\u30ff\u3400-\u4dbf\u4e00-\u9fff\u0600-\u06FF\uAC00-\uD7A3])/);
    
    const processedWords = words.map(word => {
      if (!word || word.trim() === '') return word;
     
     // 비교를 위해 소문자로 변환
     const lowerWord = word.toLowerCase().trim();
     
     // 현재 언어 키워드 가져오기
     const currentKeywords = keywordsByLanguage[selectedLanguage] || keywordsByLanguage.english;
     
     // 강조 + 툴팁 적용
     if (currentKeywords.some(keyword => lowerWord.includes(keyword) || word.includes(keyword))) {
       return `<span class="highlight-keyword tooltip" data-translation="">${word}</span>`;
     } else if (word.length > 5) {
       // 긴 단어 강조
       return `<span class="highlight-long tooltip" data-translation="">${word}</span>`;
     } else {
       // 일반 단어에 툴팁 추가
       return `<span class="tooltip" data-translation="">${word}</span>`;
     }
   });
 
   return processedWords.join('');
 }, [selectedLanguage]);
 
