 // 질문 선택 및 말하기
 const selectQuestion = useCallback(() => {
   if (!selectedCategory || !languageData?.[selectedLanguage]?.categories?.[selectedCategory]) return;
   
   // 이전 답변 및 녹음 재설정
   setAudioUrl('');
   setAudioBlob(null);
   setTranscript('');
   setFeedback('');
   setModelAnswer('');
   
   // 첫 번째 경우 진행 데이터 초기화
   if (!progressData[selectedLanguage]) {
     setProgressData(prev => ({...prev, [selectedLanguage]: {}}));
   }
   
   if (!progressData[selectedLanguage]?.[selectedCategory]) {
     setProgressData(prev => ({
       ...prev,
       [selectedLanguage]: {
         ...prev[selectedLanguage],
         [selectedCategory]: {
           total: languageData[selectedLanguage].categories[selectedCategory].length,
           answered: [],
           currentIndex: 0
         }
       }
     }));
   }
   
   // 현재 카테고리 진행 상황 가져오기
   const categoryProgress = progressData[selectedLanguage]?.[selectedCategory];
   const questions = languageData[selectedLanguage].categories[selectedCategory];
   
   // 미응답 질문 찾기
   const remainingIndexes = [];
   for (let i = 0; i < questions.length; i++) {
     if (!categoryProgress?.answered.includes(i)) {
       remainingIndexes.push(i);
     }
   }
   
   // 남은 질문에서 선택하거나 모두 답변한 경우 무작위 선택
   let selectedIndex = 0;
   if (remainingIndexes.length > 0) {
     // 미응답 질문에서 무작위 선택
     const randomIndex = Math.floor(Math.random() * remainingIndexes.length);
     selectedIndex = remainingIndexes[randomIndex];
   } else {
     // 모든 질문에 답변함, 무작위 선택
     selectedIndex = Math.floor(Math.random() * questions.length);
   }
   
   const selectedQuestion = questions[selectedIndex];
   setQuestion(selectedQuestion);
   setTranslatedQuestion('');
   
   // 현재 질문 인덱스 저장
   setProgressData(prev => ({
     ...prev,
     [selectedLanguage]: {
       ...prev[selectedLanguage],
       [selectedCategory]: {
         ...prev[selectedLanguage][selectedCategory],
         currentIndex: selectedIndex
       }
     }
   }));
   
   // 질문에서 키워드 강조
   setHighlightedQuestion(highlightKeywords(selectedQuestion));
   
   // 약간의 지연 후 질문 오디오 재생
   setTimeout(() => {
     speakWithEnhancedVoice(selectedQuestion);
   }, 500);
   
   // 응답된 카테고리 목록에 추가
   setAnsweredCategories(prev => {
     const updated = new Map(prev);
     if (!updated.has(selectedLanguage)) {
       updated.set(selectedLanguage, new Set());
     }
     updated.get(selectedLanguage).add(selectedCategory);
     return updated;
   });
 }, [
   progressData, 
   selectedCategory, 
   selectedLanguage,
   highlightKeywords,
   speakWithEnhancedVoice
 ]);
 
 // 질문 시작 버튼 클릭 핸들러
