 // AI 생성 카테고리 처리 함수
 const handleAIGeneratedCategories = (categories) => {
   // AI가 생성한 카테고리를 customCategories 형식으로 변환
   const formattedCategories = {};
   
   categories.forEach(category => {
     formattedCategories[category.name] = [...category.questions];
   });
   
   // customCategories에 추가
   setCustomCategories(prev => ({
     ...prev,
     ...formattedCategories
   }));
   
   // 생성된 카테고리 저장
   setAIGeneratedCategories(categories);
   
   // 성공 메시지 표시
   alert(`${categories.length}개의 새로운 학습 카테고리가 생성되었습니다!`);
 };
 
