 // 질문 번역
 const translateQuestion = useCallback(async () => {
   if (!question) return;
   
   try {
     setTranslatedQuestion("Translating...");
     
     // 언어 코드 가져오기
     const targetLang = languageData[translationLanguage]?.code?.split('-')[0]; // "ko-KR" -> "ko"
     const sourceLang = languageData[selectedLanguage]?.code?.split('-')[0]; // "en-US" -> "en"
     
     if (!targetLang || !sourceLang) {
       setTranslatedQuestion("Translation language codes unavailable.");
       return;
     }
     
     // MyMemory API (무료 번역 서비스)
     const myMemoryUrl = `https://api.mymemory.translated.net/get?q=${encodeURIComponent(question)}&langpair=${sourceLang}|${targetLang}`;
     const myMemoryResponse = await fetch(myMemoryUrl);
    
     if (myMemoryResponse.ok) {
       const data = await myMemoryResponse.json();
       if (data.responseData) {
         setTranslatedQuestion(data.responseData.translatedText);
         return;
       }
     }
     
     // LibreTranslate 대체
     try {
       const libreTranslateUrl = "https://libretranslate.de/translate"; // 무료 인스턴스
       const libreResponse = await fetch(libreTranslateUrl, {
         method: "POST",
         body: JSON.stringify({
           q: question,
           source: sourceLang,
           target: targetLang,
           format: "text"
         }),
         headers: { "Content-Type": "application/json" }
       });
       
       if (libreResponse.ok) {
         const libreData = await libreResponse.json();
         if (libreData.translatedText) {
           setTranslatedQuestion(libreData.translatedText);
           return;
         }
       }
     } catch (libreError) {
       console.error("LibreTranslate error:", libreError);
     }
    
     setTranslatedQuestion(`Translation service unavailable. Please try again later.`);
    
   } catch (error) {
     console.error('Translation error:', error);
     setTranslatedQuestion("Could not get translation. Please try again later.");
   }
 }, [question, selectedLanguage, translationLanguage]);
 
 // OpenAI에서 피드백 요청
 const fetchFeedback = useCallback(async () => {
  if (!apiKey) {
    alert('Please enter and save your API key first.');
    return;
  }
  
  if (!transcript) {
    alert('No speech recognized. Please record your answer again.');
    return;
  }

  setFeedback("Requesting feedback...");
  setModelAnswer("");
  
  let retries = 0;
  const maxRetries = 3;
  
  while (retries < maxRetries) {
    try {
      const response = await fetch('https://api.openai.com/v1/chat/completions', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${apiKey}`,
        },
        body: JSON.stringify({
          model: 'gpt-4-turbo',
          messages: [
            {
              role: 'user',
              content: `Question in ${languageData[selectedLanguage]?.name || 'English'}: ${question}\n\nAnswer: ${transcript}\n\nPlease provide a detailed evaluation of this answer with: 
              1) Pronunciation issues (specific words that were likely mispronounced)
              2) Grammar errors and corrections
              3) Vocabulary usage (appropriateness and variety)
              4) Fluency assessment
              5) Overall impression with a score out of 5
              6) A model answer that demonstrates proper structure and vocabulary for this question.
              
              Format your response with clear headings for each section. The model answer should be comprehensive and natural.
              Please provide the feedback in ${languageData[feedbackLanguage]?.name || 'English'}.`
            }
          ],
        }),
      });
  
      if (response.status === 429) {
        retries++;
        const waitTime = Math.pow(2, retries) * 1000;
        setFeedback(`API rate limit reached. Retrying in ${waitTime/1000} seconds...`);
        await new Promise(resolve => setTimeout(resolve, waitTime));
        continue;
      }
  
      if (!response.ok) {
        throw new Error(`HTTP error! Status: ${response.status}`);
      }
  
      const data = await response.json();
      const aiResponse = data.choices?.[0]?.message?.content || 'Unable to get response.';
      
      // 모델 답변 분리
      const modelAnswerMatch = aiResponse.match(/Model Answer:[\s\S]*$/i);
      if (modelAnswerMatch) {
        const modelAnswerContent = modelAnswerMatch[0];
        const feedbackContent = aiResponse.replace(modelAnswerMatch[0], '');
        setFeedback(feedbackContent.trim());
        setModelAnswer(modelAnswerContent.trim());
      } else {
        setFeedback(aiResponse);
      }
  
      // 연습 기록에 저장
      const practiceItem = {
        id: Date.now(),
        language: selectedLanguage,
        category: selectedCategory,
        question: question,
        answer: transcript,
        feedback: aiResponse,
        audioUrl: audioUrl,
        date: new Date().toLocaleString()
      };
     
      setPracticeHistory(prevHistory => [...prevHistory, practiceItem]);
      break;
     
    } catch (error) {
      retries++;
      if (retries >= maxRetries) {
        console.error('Feedback request error:', error);
        setFeedback('Error occurred: ' + error.message);
        break;
      }
     
      const waitTime = Math.pow(2, retries) * 1000;
      setFeedback(`Error occurred. Retrying in ${waitTime/1000} seconds...`);
      await new Promise(resolve => setTimeout(resolve, waitTime));
    }
  }
}, [apiKey, audioUrl, question, selectedCategory, selectedLanguage, transcript, feedbackLanguage]);

