// 채팅 컨텍스트 구축
const buildChatContext = useCallback(() => {
  // 시스템 메시지 (튜터 역할 정의)
  const selectedLangName = languageData[chatLanguage]?.name || 'English';
  
  let systemMessage = {
    role: 'system',
    content: `You are a professional ${selectedLangName} language tutor.
    Help the learner practice conversation in ${selectedLangName}.
    Follow these guidelines:
    
    1. Respond in ${selectedLangName} (except when the learner explicitly asks for explanations in their native language).
    2. Keep responses relatively concise and conversational.
    3. When the learner makes grammar or vocabulary errors, gently correct them by incorporating the correct expressions.
    4. Adjust language difficulty to the learner's level - avoid complex vocabulary or grammar for beginners.
    5. Ask follow-up questions to keep the conversation flowing.
    6. Provide cultural context when appropriate.
    7. Be patient, encouraging and friendly.`
  };

  // 시나리오 컨텍스트 추가
  if (scenarioType) {
    if (scenarioType === 'custom' && customScenario) {
      // 커스텀 시나리오 사용
      systemMessage.content += `\n\nCustom Scenario: ${customScenario}`;
    } else {
      // 기본 시나리오 사용
      const scenarios = {
        morning_routine: `Morning Routine Scenario: You are discussing daily morning routines. Ask about wake-up time, breakfast habits, morning preparations, and how the learner starts their day.`,
  
        school_conversation: `School Conversation Scenario: You are a fellow student or teacher at school. Discuss classes, assignments, school events, and school life in general.`,
        
        // 다른 시나리오 생략...
        restaurant: `Restaurant Ordering Scenario: You are a restaurant staff and the learner is a customer. Guide the conversation about menu recommendations, ordering, special requests, and other restaurant interactions.`,
      };
      
      systemMessage.content += `\n\n${scenarios[scenarioType] || scenarios.restaurant}`;
    }
  }
  
  // 난이도 조정 추가
  if (difficultyLevel) {
    const difficultySettings = {
      beginner: `Difficulty: Beginner - Use basic greetings, simple sentences, and everyday expressions. Keep grammar structures simple and use only common vocabulary.`,
      intermediate: `Difficulty: Intermediate - You can use more complex sentence structures and wider vocabulary. Explain if the learner seems to have difficulty understanding.`,
      advanced: `Difficulty: Advanced - Speak at a natural pace using idiomatic expressions, complex grammar, and varied vocabulary. Point out subtle errors in the learner's speech.`
    };
    
    systemMessage.content += `\n\n${difficultySettings[difficultyLevel] || difficultySettings.beginner}`;
  }
  
  // 마지막 10개 메시지만 유지 (컨텍스트 창 관리)
  const recentMessages = chatMessages.slice(-10);
  
  return [systemMessage, ...recentMessages];
}, [chatLanguage, chatMessages, difficultyLevel, scenarioType, customScenario]);
  
// GPT에 채팅 메시지 전송
const sendChatMessage = useCallback(async () => {
  if (!apiKey) {
    alert('Please enter and save your API key first.');
    return;
  }
  
  if (!chatInput.trim()) {
    return;
  }
  
  const userMessage = chatInput.trim();
  setChatInput('');
  
  // 사용자 메시지를 채팅에 추가
  const newUserMessage = {
    role: 'user',
    content: userMessage
  };
  
  setChatMessages(prevMessages => [...prevMessages, newUserMessage]);
  setIsChatProcessing(true);
  
  try {
    // 채팅 컨텍스트 구축
    const chatContext = buildChatContext();
    
    // API 요청
    const response = await fetch('https://api.openai.com/v1/chat/completions', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${apiKey}`,
      },
      body: JSON.stringify({
        model: 'gpt-4-turbo',
        messages: [
          ...chatContext,
          newUserMessage
        ],
        temperature: 0.7,
      }),
    });
  
    if (!response.ok) {
      throw new Error(`HTTP error! Status: ${response.status}`);
    }
  
    const data = await response.json();
    const assistantResponse = data.choices?.[0]?.message?.content || 'Sorry, I couldn\'t generate a response.';
    
    // 어시스턴트 응답을 채팅에 추가
    const newAssistantMessage = {
      role: 'assistant',
      content: assistantResponse
    };
    
    setChatMessages(prevMessages => [...prevMessages, newAssistantMessage]);
    
    // 상태 업데이트가 완료된 후 음성 출력을 위해 약간의 지연 추가
    setTimeout(() => {
      // 음성 출력 시도
      try {
        stopSpeech(); // 이전 음성 출력 중지
        speakWithEnhancedVoice(assistantResponse, chatPlaybackRate, true);
        console.log('응답 음성 재생 시작');
      } catch (voiceError) {
        console.error('음성 출력 오류:', voiceError);
      }
    }, 200); // 약간의 지연
    
  } catch (error) {
    console.error('Chat API request error:', error);
    
    // 오류 메시지 추가
    setChatMessages(prevMessages => [
      ...prevMessages, 
      { 
        role: 'system', 
        content: '🤖 GPT-4 Turbo로 응답 생성 중...'
      }
    ]);
  } finally {
    setIsChatProcessing(false);
  }
}, [apiKey, buildChatContext, chatInput, chatPlaybackRate, speakWithEnhancedVoice, stopSpeech]);
  
// 대화 피드백 생성
const generateConversationFeedback = async () => {
  if (!apiKey) {
    alert('OpenAI API 키를 먼저 입력해주세요.');
    return;
  }
  
  if (chatMessages.length < 3) {
    alert('충분한 대화가 없습니다. 더 대화를 나눈 후 피드백을 요청해주세요.');
    return;
  }
  
  // 대화 종료 상태로 설정
  setConversationEnded(true);
  
  // 사용자 메시지만 필터링
  const userMessages = chatMessages.filter(msg => msg.role === 'user');
  
  if (userMessages.length === 0) {
    alert('사용자 메시지가 없습니다.');
    return;
  }
  
  try {
    setIsChatProcessing(true);
    
    // 모든 사용자 메시지를 하나의 문자열로 결합
    const allUserMessages = userMessages.map(msg => msg.content).join('\n\n');
    
    // 선택된 피드백 언어 확인
    const feedbackLangName = languageData[feedbackLanguage]?.name || 'English';
    
    // OpenAI API 호출하여 종합 피드백 받기
    const response = await fetch('https://api.openai.com/v1/chat/completions', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${apiKey}`,
      },
      body: JSON.stringify({
        model: 'gpt-4-turbo', 
        messages: [
          {
            role: 'system',
            content: `당신은 ${languageData[chatLanguage]?.name || 'English'} 언어 교육 전문가입니다. 
            다음 대화에서 사용자의 메시지를 분석하고 상세한 피드백을 제공해주세요.
            
            다음 카테고리에 따라 점수(1-5)와 구체적인 피드백을 제공해주세요:
            1. 발음 및 억양 문제 (특히 잘못 발음된 단어들)
            2. 문법 오류 및 수정 방법
            3. 어휘 사용 (적절성 및 다양성)
            4. 유창성 평가
            5. 전반적인 인상
            
            각 오류에 대해 구체적인 예시와 올바른 표현을 제시해주세요.
            마지막에는 향상을 위한 조언을 추가해주세요.
            
            피드백은 ${feedbackLangName}로 작성해주세요.`
          },
          {
            role: 'user',
            content: `시나리오: ${scenarioType}\n난이도: ${difficultyLevel}\n\n사용자 메시지:\n${allUserMessages}`
          }
        ],
        temperature: 0.7,
      }),
    });
  
    if (!response.ok) {
      throw new Error(`HTTP error! Status: ${response.status}`);
    }
  
    const data = await response.json();
    const feedbackContent = data.choices?.[0]?.message?.content || '피드백을 생성할 수 없습니다.';
    
    // 피드백 메시지 추가
    setChatMessages(prev => [...prev, {
      id: Date.now(),
      role: 'feedback',
      content: feedbackContent
    }]);
    
  } catch (error) {
    console.error('Feedback Request Error:', error);
    alert('An error occurred while generating feedback: ' + error.message);
  } finally {
    setIsChatProcessing(false);
  }
};

// 대화 내용 다운로드 함수
const downloadConversation = () => {
  if (chatMessages.length === 0) {
    alert('No conversation available for download.');
    return;
  }
  
  // 대화 내용을 HTML 형식으로 변환
  let htmlContent = `
  <!DOCTYPE html>
  <html>
  <head>
    <title>${languageData[chatLanguage]?.name || 'English'} 대화 연습 기록</title>
    <meta charset="UTF-8">
    <style>
      body { font-family: Arial, sans-serif; line-height: 1.6; max-width: 800px; margin: 0 auto; padding: 20px; }
      h1 { color: #3498db; text-align: center; }
      .conversation-info { background-color: #f8f9fa; padding: 15px; border-radius: 8px; margin-bottom: 20px; }
      .message { padding: 10px 15px; margin-bottom: 10px; border-radius: 8px; }
      .user { background-color: #ebf5fb; border-left: 4px solid #3498db; }
      .assistant { background-color: #eafaf1; border-left: 4px solid #2ecc71; }
      .feedback { background-color: #fff3e0; border-left: 4px solid #f39c12; padding: 15px; margin-top: 20px; }
      .feedback h3 { color: #f39c12; }
      .date { color: #7f8c8d; font-size: 0.8em; text-align: right; }
    </style>
  </head>
  <body>
    <h1>${languageData[chatLanguage]?.flag || '🌐'} ${languageData[chatLanguage]?.name || 'English'} 대화 연습 기록</h1>
    
    <div class="conversation-info">
      <p><strong>시나리오:</strong> ${scenarioType}</p>
      <p><strong>난이도:</strong> ${difficultyLevel}</p>
      <p><strong>날짜:</strong> ${new Date().toLocaleString()}</p>
    </div>
    
    <div class="conversation">
  `;

  // 각 메시지를 HTML로 변환
  chatMessages.forEach(message => {
    if (message.role === 'feedback') {
      htmlContent += `
      <div class="feedback">
        <h3>🎓 종합 피드백</h3>
        <div>${message.content.replace(/\n/g, '<br>')}</div>
      </div>`;
    } else {
      htmlContent += `
      <div class="message ${message.role}">
        <strong>${message.role === 'user' ? '나' : '튜터'}:</strong>
        <div>${message.content}</div>
      </div>`;
    }
  });

  htmlContent += `
    </div>
  </body>
  </html>
  `;

  // HTML 파일로 다운로드
  const blob = new Blob([htmlContent], { type: 'text/html' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = `${languageData[chatLanguage]?.name || 'English'}_대화_${new Date().toLocaleDateString().replace(/\//g, '-')}.html`;
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  URL.revokeObjectURL(url);
};

