// ===== HISTORY & EXPORT FUNCTIONS =====
// 기록을 HTML/PPT로 내보내기
const exportToPPT = useCallback(() => {
  if (practiceHistory.length === 0) {
    alert('No practice records to export.');
    return;
  }

  let pptHtml = `
  <!DOCTYPE html>
  <html>
  <head>
    <title>Multilingual Speaking Practice Records</title>
    <style>
      body { font-family: Arial, sans-serif; }
      .slide { page-break-after: always; padding: 20px; border: 1px solid #ddd; margin-bottom: 20px; }
      h1 { color: #2c3e50; }
      h2 { color: #3498db; }
      .question { background-color: #f8f9fa; padding: 10px; border-left: 5px solid #3498db; }
      .answer { background-color: #f1f8e9; padding: 10px; border-left: 5px solid #4caf50; }
      .feedback { background-color: #fff8e1; padding: 10px; border-left: 5px solid #ffc107; }
      .date { color: #7f8c8d; font-size: 0.8em; }
      .language-flag { font-size: 1.5em; margin-right: 10px; }
    </style>
  </head>
  <body>
    <h1>Multilingual Speaking Practice Records</h1>
  `;

  practiceHistory.forEach((item, index) => {
    const langInfo = languageData[item.language] || {flag: "🌐", name: "Unknown"};
    pptHtml += `
    <div class="slide">
      <h2><span class="language-flag">${langInfo.flag}</span> Practice #${index + 1} - ${item.category}</h2>
      <p class="date">Date: ${item.date} | Language: ${langInfo.name}</p>
      <div class="question">
        <h3>Question:</h3>
        <p>${item.question}</p>
      </div>
      <div class="answer">
        <h3>Response:</h3>
        <p>${item.answer}</p>
      </div>
      <div class="feedback">
        <h3>Feedback:</h3>
        <p>${item.feedback}</p>
      </div>
    </div>
    `;
  });

  pptHtml += `
  </body>
  </html>
  `;

  const blob = new Blob([pptHtml], { type: 'text/html' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = 'Multilingual_Practice_Records.html';
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  URL.revokeObjectURL(url);
}, [practiceHistory]);

// ===== CATEGORY PAGING FUNCTIONS =====
const getCurrentPageCategories = useCallback(() => {
  const allCategories = Object.keys(languageData[selectedLanguage]?.categories || {});
  const startIndex = currentCategoryPage * CATEGORIES_PER_PAGE;
  return allCategories.slice(startIndex, startIndex + CATEGORIES_PER_PAGE);
}, [currentCategoryPage, selectedLanguage, CATEGORIES_PER_PAGE]);

const nextCategoryPage = useCallback(() => {
  const totalPages = Math.ceil(Object.keys(languageData[selectedLanguage]?.categories || {}).length / CATEGORIES_PER_PAGE);
  if (currentCategoryPage < totalPages - 1) {
    setCurrentCategoryPage(currentCategoryPage + 1);
  }
}, [currentCategoryPage, selectedLanguage, CATEGORIES_PER_PAGE]);

const prevCategoryPage = useCallback(() => {
  if (currentCategoryPage > 0) {
    setCurrentCategoryPage(currentCategoryPage - 1);
  }
}, [currentCategoryPage]);

// 전체 카테고리 페이지 계산
const totalCategoryPages = useMemo(() => 
  Math.ceil(Object.keys(languageData[selectedLanguage]?.categories || {}).length / CATEGORIES_PER_PAGE),
[selectedLanguage, CATEGORIES_PER_PAGE]);

