import React, { useState, useEffect } from 'react';
import './QuizSystem.css';

const QuizResult = ({ quizData, userAnswers, restartQuiz, retryIncorrectQuestions, onClose, language, feedbackLanguage }) => {
  const [score, setScore] = useState(0);
  const [weakPoints, setWeakPoints] = useState([]);
  const [showAnimation, setShowAnimation] = useState(false);
  const [correctAnswers, setCorrectAnswers] = useState([]);
  const [incorrectAnswers, setIncorrectAnswers] = useState([]);
  const [detailedFeedback, setDetailedFeedback] = useState(false);
  
  // 정답 비교 기능 개선 - 명확하고 엄격한 비교로 변경
  const isAnswerCorrect = (userAnswer, correctAnswer) => {
    // 입력값이 없는 경우 처리
    if (!userAnswer || !correctAnswer) {
      return false;
    }
    
    // 디버그 로그 추가 - 입력값 확인
    console.log('정답 비교 시작:', { userAnswer, correctAnswer });
    
    // 문자열 정규화 (모든 비교는 소문자와 공백 제거로 표준화)
    const normalizeString = (str) => {
      if (typeof str !== 'string') return String(str).trim().toLowerCase();
      return str.trim().toLowerCase();
    };
    
    // 정답 정규화
    const normalizedCorrectAnswer = normalizeString(correctAnswer);
    
    // 사용자 답변이 객체인 경우 (선택지 ID와 텍스트를 모두 확인)
    if (typeof userAnswer === 'object') {
      // 객체의 핵심 속성 검사
      const userAnswerId = userAnswer.id ? normalizeString(userAnswer.id) : '';
      const userAnswerText = userAnswer.text ? normalizeString(userAnswer.text) : '';
      const isCorrectFlag = userAnswer.isCorrect === true;
      
      // 디버그 로그
      console.log('객체 정답 비교:', {
        userAnswerText,
        userAnswerId, 
        isCorrectFlag,
        normalizedCorrectAnswer
      });
      
      // isCorrect 플래그가 명시적으로 true인 경우 (신뢰할 수 있는 정보)
      if (isCorrectFlag) {
        return true;
      }
      
      // 옵션 ID가 A, B, C, D이고 정답도 A, B, C, D 형식인 경우
      if (userAnswerId.length === 1 && normalizedCorrectAnswer.length === 1) {
        return userAnswerId === normalizedCorrectAnswer;
      }
      
      // 텍스트 정확히 일치하는 경우
      if (userAnswerText === normalizedCorrectAnswer) {
        return true;
      }
      
      return false;
    } 
    // 문자열 비교 (일반적인 경우)
    else {
      const normalizedUserAnswer = normalizeString(userAnswer);
      
      // 디버그 로그
      console.log('문자열 정답 비교:', {
        normalizedUserAnswer, 
        normalizedCorrectAnswer
      });
      
      // 정확한 일치
      return normalizedUserAnswer === normalizedCorrectAnswer;
    }
  };
  
  // 결과 데이터 계산
  useEffect(() => {
    // 점수 계산
    console.log("사용자 답변 전체:", userAnswers);
    console.log("정답 전체:", quizData.quiz.map(q => q.answer));

    const correctItems = [];
    const incorrectItems = [];

    // 정답 개수 계산 - 개선된 비교 로직 사용
    const correctCount = quizData.quiz.reduce((count, question, index) => {
      // 사용자 답변
      const userAnswer = userAnswers[index];
      // 정답
      const correctAnswer = question.answer;
      
      console.log(`질문 ${index+1}: 사용자 답변 "${typeof userAnswer === 'object' ? JSON.stringify(userAnswer) : userAnswer}", 정답 "${correctAnswer}"`);
      
      // 개선된 정답 비교 함수 사용
      const isCorrect = isAnswerCorrect(userAnswer, correctAnswer);
      
      // 디버그 로그 추가
      console.log(`질문 ${index+1} 정답 여부:`, isCorrect);
      
      // 정답/오답 항목 구분하여 저장
      if (isCorrect) {
        correctItems.push(index);
      } else {
        incorrectItems.push(index);
      }
      
      return isCorrect ? count + 1 : count;
    }, 0);
    
    setCorrectAnswers(correctItems);
    setIncorrectAnswers(incorrectItems);
    
    // 점수 계산 - 백분율 정확히 계산 (맞은 문제 / 전체 문제 * 100)
    const totalQuestions = quizData.quiz.length;
    const calculatedScore = totalQuestions > 0 ? Math.round((correctCount / totalQuestions) * 100) : 0;
    console.log(`정확한 점수 계산: ${correctCount}/${totalQuestions} = ${calculatedScore}%`);
    
    setScore(calculatedScore);
    
    // 취약점 분석 (오답에서 패턴 찾기)
    const incorrectQuestions = quizData.quiz.filter((question, index) => {
      const userAnswer = userAnswers[index];
      const correctAnswer = question.answer;
      
      // 개선된 정답 비교 함수 사용
      return !isAnswerCorrect(userAnswer, correctAnswer);
    });
    
    // 간단한 취약점 분석을 위한 키워드 추출 (해설에서 중요 내용 추출)
    const keywords = incorrectQuestions.map(q => {
      // 설명에서 중요 키워드 추출 (간단한 구현을 위해 첫 문장만 사용)
      const firstSentence = q.explanation?.split('.')[0] || '';
      return firstSentence;
    });
    
    setWeakPoints(keywords);
    
    // 애니메이션 표시
    setTimeout(() => {
      setShowAnimation(true);
    }, 500);
  }, [quizData, userAnswers]);
  
  // 피드백 표시 토글
  const toggleDetailedFeedback = () => {
    setDetailedFeedback(!detailedFeedback);
  };
  
  // 언어에 따른 텍스트 반환
  const getLocalizedText = (key) => {
    const texts = {
      excellent: {
        english: "Excellent! You have a great understanding of this topic.",
        korean: "훌륭합니다! 이 주제에 대한 이해도가 매우 높습니다.",
        japanese: "素晴らしい！このトピックをよく理解しています。",
        chinese: "太棒了！您对这个主题有很好的理解。",
        spanish: "¡Excelente! Tienes una gran comprensión de este tema.",
        french: "Excellent ! Vous avez une excellente compréhension de ce sujet.",
        german: "Ausgezeichnet! Sie haben ein großartiges Verständnis dieses Themas.",
        russian: "Отлично! У вас отличное понимание этой темы.",
        arabic: "ممتاز! لديك فهم رائع لهذا الموضوع.",
        vietnamese: "Tuyệt vời! Bạn có sự hiểu biết tốt về chủ đề này.",
        thai: "ยอดเยี่ยม! คุณมีความเข้าใจที่ดีเกี่ยวกับหัวข้อนี้",
        indonesian: "Luar biasa! Anda memiliki pemahaman yang baik tentang topik ini."
      },
      good: {
        english: "Good job! Keep practicing to improve further.",
        korean: "잘했습니다! 더 향상되도록 계속 연습하세요.",
        japanese: "よくできました！さらに向上するために練習を続けてください。",
        chinese: "做得好！继续练习以进一步提高。",
        spanish: "¡Buen trabajo! Sigue practicando para mejorar más.",
        french: "Bon travail ! Continuez à pratiquer pour vous améliorer davantage.",
        german: "Gute Arbeit! Üben Sie weiter, um sich weiter zu verbessern.",
        russian: "Хорошая работа! Продолжайте практиковаться, чтобы улучшить результаты.",
        arabic: "عمل جيد! استمر في الممارسة للتحسن أكثر.",
        vietnamese: "Làm tốt lắm! Tiếp tục luyện tập để cải thiện hơn nữa.",
        thai: "ทำได้ดี! ฝึกฝนต่อไปเพื่อพัฒนาให้ดียิ่งขึ้น",
        indonesian: "Kerja bagus! Terus berlatih untuk meningkatkan lebih lanjut."
      },
      fair: {
        english: "Fair effort. Focus on the areas where you made mistakes.",
        korean: "괜찮은 노력입니다. 실수한 부분에 집중하세요.",
        japanese: "まあまあの努力です。間違えた箇所に集中してください。",
        chinese: "努力不错。专注于您犯错的领域。",
        spanish: "Esfuerzo aceptable. Concéntrate en las áreas donde cometiste errores.",
        french: "Effort passable. Concentrez-vous sur les domaines où vous avez fait des erreurs.",
        german: "Angemessene Leistung. Konzentrieren Sie sich auf die Bereiche, in denen Sie Fehler gemacht haben.",
        russian: "Неплохая попытка. Сосредоточьтесь на областях, где вы допустили ошибки.",
        arabic: "جهد مقبول. ركز على المجالات التي ارتكبت فيها أخطاء.",
        vietnamese: "Nỗ lực khá tốt. Tập trung vào các lĩnh vực bạn mắc lỗi.",
        thai: "ความพยายามที่ดี เน้นที่จุดที่คุณทำผิดพลาด",
        indonesian: "Usaha yang cukup. Fokus pada area di mana Anda membuat kesalahan."
      },
      needsImprovement: {
        english: "Needs improvement. Try reviewing the basics and practice more.",
        korean: "개선이 필요합니다. 기본 사항을 복습하고 더 연습해 보세요.",
        japanese: "改善が必要です。基本に戻って練習を重ねてみてください。",
        chinese: "需要改进。尝试复习基础知识并多加练习。",
        spanish: "Necesita mejorar. Intenta repasar los conceptos básicos y practica más.",
        french: "Nécessite une amélioration. Essayez de revoir les bases et pratiquez davantage.",
        german: "Verbesserungsbedürftig. Versuchen Sie, die Grundlagen zu wiederholen und mehr zu üben.",
        russian: "Требуется улучшение. Попробуйте повторить основы и больше практиковаться.",
        arabic: "يحتاج إلى تحسين. حاول مراجعة الأساسيات وممارسة المزيد.",
        vietnamese: "Cần cải thiện. Hãy xem lại kiến thức cơ bản và luyện tập nhiều hơn.",
        thai: "ต้องปรับปรุง ลองทบทวนพื้นฐานและฝึกฝนให้มากขึ้น",
        indonesian: "Perlu perbaikan. Cobalah meninjau dasar-dasar dan berlatih lebih banyak."
      },
      weakPoints: {
        english: "Areas to Improve",
        korean: "개선해야 할 영역",
        japanese: "改善すべき分野",
        chinese: "需要改进的领域",
        spanish: "Áreas a Mejorar",
        french: "Domaines à Améliorer",
        german: "Verbesserungsbereiche",
        russian: "Области для улучшения",
        arabic: "مجالات للتحسين",
        vietnamese: "Lĩnh vực cần cải thiện",
        thai: "จุดที่ควรปรับปรุง",
        indonesian: "Area untuk Ditingkatkan"
      },
      retry: {
        english: "Retry Incorrect Questions",
        korean: "틀린 문제 다시 풀기",
        japanese: "間違った問題をやり直す",
        chinese: "重试错误的问题",
        spanish: "Reintentar Preguntas Incorrectas",
        french: "Réessayer les Questions Incorrectes",
        german: "Falsche Fragen wiederholen",
        russian: "Повторить неправильные вопросы",
        arabic: "إعادة محاولة الأسئلة غير الصحيحة",
        vietnamese: "Thử lại câu hỏi sai",
        thai: "ลองทำคำถามที่ผิดอีกครั้ง",
        indonesian: "Coba Lagi Pertanyaan yang Salah"
      },
      newQuiz: {
        english: "New Quiz",
        korean: "새 퀴즈",
        japanese: "新しいクイズ",
        chinese: "新测验",
        spanish: "Nuevo Cuestionario",
        french: "Nouveau Quiz",
        german: "Neues Quiz",
        russian: "Новый тест",
        arabic: "اختبار جديد",
        vietnamese: "Bài kiểm tra mới",
        thai: "แบบทดสอบใหม่",
        indonesian: "Kuis Baru"
      },
      close: {
        english: "Close",
        korean: "닫기",
        japanese: "閉じる",
        chinese: "关闭",
        spanish: "Cerrar",
        french: "Fermer",
        german: "Schließen",
        russian: "Закрыть",
        arabic: "إغلاق",
        vietnamese: "Đóng",
        thai: "ปิด",
        indonesian: "Tutup"
      },
      showFeedback: {
        english: "Show Detailed Feedback",
        korean: "상세 피드백 보기",
        japanese: "詳細なフィードバックを表示",
        chinese: "显示详细反馈",
        spanish: "Mostrar Retroalimentación Detallada",
        french: "Afficher les Commentaires Détaillés",
        german: "Detailliertes Feedback anzeigen",
        russian: "Показать подробную обратную связь",
        arabic: "عرض التعليقات المفصلة",
        vietnamese: "Hiển thị phản hồi chi tiết",
        thai: "แสดงข้อเสนอแนะโดยละเอียด",
        indonesian: "Tampilkan Umpan Balik Terperinci"
      },
      hideFeedback: {
        english: "Hide Detailed Feedback",
        korean: "상세 피드백 숨기기",
        japanese: "詳細なフィードバックを隠す",
        chinese: "隐藏详细反馈",
        spanish: "Ocultar Retroalimentación Detallada",
        french: "Masquer les Commentaires Détaillés",
        german: "Detailliertes Feedback ausblenden",
        russian: "Скрыть подробную обратную связь",
        arabic: "إخفاء التعليقات المفصلة",
        vietnamese: "Ẩn phản hồi chi tiết",
        thai: "ซ่อนข้อเสนอแนะโดยละเอียด",
        indonesian: "Sembunyikan Umpan Balik Terperinci"
      }
    };
    
    const lang = feedbackLanguage || language || 'english';
    return texts[key][lang] || texts[key].english;
  };

  // 사용자 답변 텍스트 표시 함수
  const formatUserAnswer = (userAnswer) => {
    if (!userAnswer) return "No answer";
    
    if (typeof userAnswer === 'object') {
      if (userAnswer.text) {
        return userAnswer.text;
      } else if (userAnswer.id) {
        return `Option ${userAnswer.id}`;
      } else {
        return JSON.stringify(userAnswer);
      }
    }
    
    return String(userAnswer);
  };

  // 피드백 토글 버튼만 표시
  return (
    <div className="quiz-result-container">
      <div className="feedback-toggle">
        <button 
          onClick={toggleDetailedFeedback} 
          className={`feedback-toggle-button ${detailedFeedback ? 'active' : ''}`}
        >
          {detailedFeedback ? getLocalizedText('hideFeedback') : getLocalizedText('showFeedback')}
        </button>
      </div>
      
      {/* 약점 분석 (선택적으로 표시) */}
      {detailedFeedback && weakPoints.length > 0 && (
        <div className="weak-points-container">
          <h3>{getLocalizedText('weakPoints')}</h3>
          <ul className="weak-points-list">
            {weakPoints.map((point, index) => (
              <li key={index}>{point}</li>
            ))}
          </ul>
        </div>
      )}
      
      {/* 상세 피드백 (요청 시에만 표시) */}
      {detailedFeedback && (
        <div className="result-details">
          {quizData.quiz.map((question, index) => {
            // 정답 여부 확인 - 개선된 함수 사용
            const userAnswer = userAnswers[index];
            const correctAnswer = question.answer;
            const isCorrect = isAnswerCorrect(userAnswer, correctAnswer);
            
            return (
              <div key={index} className={`result-question ${isCorrect ? 'correct' : 'incorrect'}`}>
                <div className="result-question-number">Q{index + 1}</div>
                <div className="result-question-text">{question.question}</div>
                <div className="result-answer">
                  <span className="result-user-answer">
                    Your answer: <strong>{formatUserAnswer(userAnswer)}</strong>
                  </span>
                  {!isCorrect && (
                    <span className="result-correct-answer">
                      Correct answer: <strong>{correctAnswer}</strong>
                    </span>
                  )}
                </div>
                <div className="result-explanation">
                  <h4>Explanation:</h4>
                  <p>{question.explanation}</p>
                </div>
              </div>
            );
          })}
        </div>
      )}
      
      <div className="result-actions">
        <button onClick={retryIncorrectQuestions} className="retry-incorrect-button">
          {getLocalizedText('retry')}
        </button>
        <button onClick={restartQuiz} className="new-quiz-button">
          {getLocalizedText('newQuiz')}
        </button>
        <button onClick={onClose} className="close-quiz-button">
          {getLocalizedText('close')}
        </button>
      </div>
    </div>
  );
};

export default QuizResult;