// 개발 모드에서 콘솔 로그 출력 활성화
const DEBUG = true;

// 안정적인 콘솔 로그 함수
const logInfo = (message, data) => {
  if (DEBUG) {
    if (data) {
      console.log(`[AITest] ${message}`, data);
    } else {
      console.log(`[AITest] ${message}`);
    }
  }
};

// 안드로이드 최적화 음성 인식 시작 함수
const startAndroidOptimizedRecognition = (recognition, setIsRecording) => {
  if (!recognition) return false;
  
  try {
    // 이미 진행 중일 수 있으므로 안전하게 중지
    try {
      recognition.stop();
      console.log("기존 인식기 중지함");
    } catch (e) {
      // 이미 중지된 상태는 무시
      console.log("이미 중지된 상태:", e);
    }
    
    // 약간의 지연 후 재시작 - 안드로이드에서 필수
    setTimeout(() => {
      try {
        recognition.start();
        console.log("안드로이드 인식기 시작됨");
        setIsRecording(true);
        return true;
      } catch (error) {
        console.error('인식 시작 오류:', error);
        
        // 한 번 더 시도
        setTimeout(() => {
          try {
            recognition.start();
            console.log("두 번째 시도 성공");
            setIsRecording(true);
            return true;
          } catch (retryError) {
            console.error('두 번째 시도 실패:', retryError);
            setIsRecording(false);
            return false;
          }
        }, 500);
      }
    }, 300);
    
    return true;
  } catch (error) {
    console.error('안드로이드 인식 초기화 오류:', error);
    return false;
  }
};

// 커튼식 팝업 샘플 답변 컴포넌트
const SampleResponseCurtain = ({ sample, isOpen, toggleSample }) => {
  // 팝업 애니메이션 참조
  const curtainRef = useRef(null);

  // 애니메이션 효과
  useEffect(() => {
    if (curtainRef.current) {
      if (isOpen) {
        curtainRef.current.style.maxHeight = `${curtainRef.current.scrollHeight}px`;
        curtainRef.current.style.opacity = '1';
      } else {
        curtainRef.current.style.maxHeight = '0';
        curtainRef.current.style.opacity = '0';
      }
    }
  }, [isOpen]);

  return (
    <div className="sample-response-container">
      <button 
        className={`sample-toggle-button ${isOpen ? 'active' : ''}`}
        onClick={toggleSample}
      >
        <span>{isOpen ? '샘플 닫기' : '샘플 보기'}</span>
        <i className={`fas fa-chevron-${isOpen ? 'up' : 'down'}`}></i>
      </button>
      <div 
        ref={curtainRef} 
        className={`sample-curtain ${isOpen ? 'open' : ''}`}
      >
        <div className="sample-content">
          <i className="fas fa-lightbulb sample-icon"></i>
          <div className="sample-text">{sample || '샘플 응답을 불러오는 중...'}</div>
        </div>
      </div>
    </div>
  );
};

