  // 안드로이드 디바이스 감지
  const isAndroid = useRef(/Android/i.test(navigator.userAgent));

  // REFS
  const recognitionRef = useRef(null);
  const mediaRecorderRef = useRef(null);
  const audioChunksRef = useRef([]);
  const continuousRecognitionRef = useRef(false); // 안드로이드용 연속 인식 상태 추적
  const downloadLinkRef = useRef(null); // HTML 다운로드 링크 참조

  // EFFECTS
  // Initialize voices
  useEffect(() => {
    const initVoices = () => {
      const voices = window.speechSynthesis.getVoices();
      setAvailableVoices(voices);
      console.log("Available voices:", voices.map(v => `${v.name} (${v.lang})`));
    };

    if (window.speechSynthesis) {
      window.speechSynthesis.onvoiceschanged = initVoices;
      
      // Try to load initially
      setTimeout(() => {
        if (window.speechSynthesis.getVoices().length > 0) {
          initVoices();
        }
      }, 200);
    }
    
    return () => {
      if (window.speechSynthesis) {
        window.speechSynthesis.onvoiceschanged = null;
      }
    };
  }, []);

  // Timer handling
// Timer handling
useEffect(() => {
  let timer;
  if (testTimerActive && timeRemaining > 0) {
    timer = setTimeout(() => {
      setTimeRemaining(prev => prev - 1);
    }, 1000);
  } else if (testTimerActive && timeRemaining === 0) {
    stopRecording();
    setTestTimerActive(false);
    
    // 자동으로 다음 단계로 진행하기 전에 응답 유효성 확인
    setTimeout(() => {
      if (transcript.trim()) {
        // 응답이 있으면 정상 진행
        saveCurrentResponse();
      } else {
        // 응답이 없으면 사용자에게 알림
        const alertBox = document.createElement('div');
        alertBox.className = 'response-alert-box';
        alertBox.innerHTML = `
          <div class="response-alert-content">
            <div class="alert-icon">⚠️</div>
            <div class="alert-message">
              <h4>응답이 감지되지 않았습니다</h4>
              <p>시간이 종료되었지만 응답이 녹음되지 않았습니다. 다시 응답해 주세요.</p>
            </div>
            <button class="alert-close-btn">확인</button>
          </div>
        `;
        
        document.body.appendChild(alertBox);
        
        // 확인 버튼 클릭 이벤트 처리
        const closeBtn = alertBox.querySelector('.alert-close-btn');
        closeBtn.addEventListener('click', () => {
          alertBox.classList.add('fadeout');
          setTimeout(() => {
            document.body.removeChild(alertBox);
          }, 300);
        });
        
        // 모달창이 나타날 때 애니메이션 적용
        setTimeout(() => {
          alertBox.classList.add('visible');
        }, 10);
        
        // 테스트는 계속 진행 중 상태로 유지
        setIsTestInProgress(true);
        setQuestionGenerated(true);
        
        // 사용자가 다시 응답할 수 있도록 타이머 재설정
        // 원래 시간의 1/3만 제공하여 추가 응답 기회 부여
        const originalTime = currentTest.parts[testPart - 1].answerTime;
        setTimeRemaining(Math.ceil(originalTime / 3));
      }
    }, 500); // 녹음 중지 후 약간의 지연 시간을 두고 확인
  }
  
  return () => clearTimeout(timer);
}, [testTimerActive, timeRemaining, transcript, currentTest, testPart, stopRecording, saveCurrentResponse]);

  // 피드백 언어 변경 감지 및 적용
  useEffect(() => {
    if (feedbackLanguage) {
      setLocalFeedbackLanguage(feedbackLanguage);
    }
  }, [feedbackLanguage]);

  // 테스트 타입이 변경되면 질문 히스토리 초기화
  useEffect(() => {
    setAskedQuestions({});
    setQuestionTopics([]); // 질문 주제도 초기화
  }, [testType]);
  
  // partCompleted 상태가 변경될 때 자동으로 다음 파트로 이동 (파트별 피드백 없이)
  useEffect(() => {
    if (partCompleted && !isTestInProgress) {
      // 다음 파트로 자동 이동
      if (testPart < mockTestData[testType].parts.length) {
        // 다음 파트로 자동 이동
        setTestPart(testPart + 1);
        setCurrentQuestionIndex(0);
        setPartCompleted(false);
      } else {
        // 모든 파트가 완료됨 - 테스트 완료 및 즉시 종합 평가 생성
        setTestCompleted(true);
        handleGenerateSummaryReport();
      }
    }
  }, [partCompleted, testPart, testType]);
  
  // FUNCTIONS
  // Speech recognition setup
const setupSpeechRecognition = useCallback(() => {
  if (!('webkitSpeechRecognition' in window) && !('SpeechRecognition' in window)) {
    console.warn('This browser does not support speech recognition.');
    return;
  }
  
  if (recognitionRef.current) {
    try {
      recognitionRef.current.stop();
    } catch (e) {}
    
    recognitionRef.current.onresult = null;
    recognitionRef.current.onend = null;
    recognitionRef.current.onerror = null;
  }
  
  const currentTestLanguage = mockTestData[testType]?.language || selectedLanguage;
  const langCode = languageData[currentTestLanguage]?.code || 'en-US';
  
  // Create speech recognition instance
  const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
  const recognition = new SpeechRecognition();
  
  // 안드로이드 디바이스 최적화 설정
  if (isAndroid.current) {
    recognition.continuous = false;  // 안드로이드에서는 continuous를 false로 설정
    recognition.interimResults = true;
    recognition.maxAlternatives = 3; // 안드로이드에서 대체 결과 수 증가
    logInfo("안드로이드 최적화 설정 적용됨");
  } else {
    recognition.continuous = true;
    recognition.interimResults = true;
  }
  
  recognition.lang = langCode;
  logInfo("인식 언어 설정:", langCode);
  
  // 결과 처리 로직 강화
  recognition.onresult = (event) => {
    logInfo("인식 결과 받음", event.results.length);
    let interimTranscript = '';
    let finalTranscript = '';
    
    for (let i = event.resultIndex; i < event.results.length; ++i) {
      if (event.results[i].isFinal) {
        finalTranscript += event.results[i][0].transcript;
        logInfo("최종 결과:", finalTranscript);
      } else {
        interimTranscript += event.results[i][0].transcript;
      }
    }
    
    // 어떤 결과든 상태 업데이트
    const combinedTranscript = finalTranscript || interimTranscript;
    if (combinedTranscript.trim()) {
      setTranscript(prev => {
        // 최종 결과만 이전 텍스트에 추가
        if (finalTranscript) {
          return prev + finalTranscript + ' ';
        }
        // 임시 결과는 이전 내용 유지
        return prev;
      });
    }
  };
  
  // 안드로이드용 onend 처리 개선
  recognition.onend = () => {
    logInfo("음성 인식 종료됨");
    
    // 안드로이드에서 자동 종료 처리 개선
    if (isAndroid.current && continuousRecognitionRef.current) {
      logInfo("안드로이드 연속 인식 - 재시작 시도");
      try {
        // 연속 모드에서는 약간의 지연 후 자동 재시작
        setTimeout(() => {
          try {
            recognition.start();
            logInfo("안드로이드 인식기 재시작 성공");
          } catch (error) {
            console.error('인식기 재시작 실패:', error);
            // 실패하면 다시 시도
            setTimeout(() => {
              try {
                recognition.start();
                logInfo("두 번째 재시작 시도 성공");
              } catch(retryError) {
                console.error('두 번째 재시작 실패:', retryError);
                setIsRecording(false);
                continuousRecognitionRef.current = false;
              }
            }, 500); 
          }
        }, 300);
      } catch (error) {
        console.error('인식 재시작 처리 오류:', error);
        setIsRecording(false);
        continuousRecognitionRef.current = false;
      }
    } else {
      // 연속 모드가 아니거나 안드로이드가 아닌 경우
      setIsRecording(false);
    }
  };
  
  recognition.onerror = (event) => {
    console.error('Speech recognition error', event.error, event);
    
    // 오류 유형별 처리
    if (event.error === 'network') {
      logInfo("네트워크 오류가 발생했습니다. 인터넷 연결을 확인하세요.");
    } else if (event.error === 'no-speech') {
      logInfo("음성이 감지되지 않았습니다. 마이크에 더 가까이 말씀해보세요.");
    } else if (event.error === 'not-allowed') {
      logInfo("마이크 사용 권한이 거부되었습니다. 브라우저 설정에서 권한을 허용해주세요.");
    }
    
    setIsRecording(false);
  };
  
  recognitionRef.current = recognition;
}, [testType, selectedLanguage]);

// Start recording - 안드로이드 최적화 버전
const startRecording = useCallback(async () => {
  try {
    // If already recording, stop first
    if (isRecording) {
      stopRecording();
      // 중요: 이전 녹음이 완전히 중지될 시간을 주기
      await new Promise(resolve => setTimeout(resolve, 300));
    }
    
    logInfo("시작: 음성 녹음 시작");
    setAudioUrl('');
    setTranscript('');
    
    // 명시적으로 음성 인식 설정
    setupSpeechRecognition();
    
    const stream = await navigator.mediaDevices.getUserMedia({ 
      audio: {
        echoCancellation: true,
        noiseSuppression: true,
        autoGainControl: true
      } 
    });
    
    // 안드로이드용 MIME 타입 확인
    let mimeType = 'audio/webm';
    if (isAndroid.current) {
      if (MediaRecorder.isTypeSupported('audio/webm')) {
        mimeType = 'audio/webm';
      } else if (MediaRecorder.isTypeSupported('audio/mp4')) {
        mimeType = 'audio/mp4';
      } else if (MediaRecorder.isTypeSupported('audio/ogg')) {
        mimeType = 'audio/ogg';
      }
    }
    
    logInfo(`사용 MIME 타입: ${mimeType}`);
    mediaRecorderRef.current = new MediaRecorder(stream, {
      mimeType: mimeType
    });
    
    audioChunksRef.current = [];
    
    mediaRecorderRef.current.ondataavailable = (event) => {
      if (event.data.size > 0) {
        audioChunksRef.current.push(event.data);
        logInfo(`오디오 청크 받음: ${event.data.size} 바이트`);
      }
    };
    
    mediaRecorderRef.current.onstop = () => {
      const chunks = audioChunksRef.current;
      logInfo(`녹음 완료: ${chunks.length} 청크, 총 ${chunks.reduce((acc, chunk) => acc + chunk.size, 0)} 바이트`);
      
      try {
        const audioBlob = new Blob(chunks, { type: mimeType });
        const audioUrl = URL.createObjectURL(audioBlob);
        setAudioUrl(audioUrl);
      } catch (error) {
        console.error('Blob 생성 오류:', error);
      }
    };
    
    // 레코더 시작
    mediaRecorderRef.current.start(100);
    
    // 중요: 안드로이드용 최적화된 연속 인식 설정
    if (isAndroid.current) {
      continuousRecognitionRef.current = true;
      logInfo("안드로이드 연속 인식 활성화");
      
      // 인식기 시작 전에 확실히 설정
      if (recognitionRef.current) {
        startAndroidOptimizedRecognition(recognitionRef.current, setIsRecording);
      } else {
        console.error('인식기가 초기화되지 않음');
      }
    } else {
      // 비안드로이드
      if (recognitionRef.current) {
        try {
          recognitionRef.current.start();
          setIsRecording(true);
        } catch (error) {
          console.error('Speech recognition start error:', error);
        }
      }
    }
  } catch (err) {
    console.error("Recording error:", err);
    alert("Could not access microphone. Please check your microphone permissions.");
  }
}, [isRecording, setupSpeechRecognition]);
    
// Stop recording
const stopRecording = useCallback(() => {
  logInfo("녹음 중지 시작");
  // 연속 인식 중지 플래그 설정
  continuousRecognitionRef.current = false;
  
  // 음성 인식 중지
  if (recognitionRef.current) {
    try {
      recognitionRef.current.stop();
      logInfo("음성 인식 중지됨");
    } catch (error) {
      console.error('음성 인식 중지 오류:', error);
    }
  }
  
  // 미디어 레코더 중지
  if (mediaRecorderRef.current && mediaRecorderRef.current.state === 'recording') {
    logInfo("미디어 레코더 중지 시작");
    try {
      mediaRecorderRef.current.stop();
      logInfo("미디어 레코더 중지됨");
      
      if (mediaRecorderRef.current.stream) {
        mediaRecorderRef.current.stream.getTracks().forEach(track => {
          track.stop();
          logInfo("미디어 트랙 중지됨");
        });
      }
    } catch (error) {
      console.error("미디어 레코더 중지 오류:", error);
    }
  }
  
  setIsRecording(false);
  logInfo("녹음 중지 완료");
}, []);

// Get the appropriate voice based on language
const getEnhancedVoice = useCallback(() => {
  const voices = availableVoices.length > 0 ? 
    availableVoices : 
    window.speechSynthesis.getVoices();
  
  const currentTestLanguage = mockTestData[testType]?.language || selectedLanguage;
  const currentLangCode = languageData[currentTestLanguage]?.code || 'en-US';
  
  let voicePool = voices.filter(v => v.lang.includes(currentLangCode));
  
  return voicePool.length > 0 ? voicePool[0] : voices[0];
}, [availableVoices, testType, selectedLanguage]);

// Enhanced voice synthesis
const speakWithEnhancedVoice = useCallback((text, rate = questionPlaybackRate) => {
  if (window.speechSynthesis.speaking) {
    window.speechSynthesis.cancel();
  }
  
  const currentTestLanguage = mockTestData[testType]?.language || selectedLanguage;
  const currentLangCode = languageData[currentTestLanguage]?.code || 'en-US';
  
  console.log("Current language:", currentTestLanguage, "language code:", currentLangCode);
  console.log("Text:", text);
  console.log("Speech rate:", rate);
  
  const utterance = new SpeechSynthesisUtterance(text);
  
  utterance.lang = currentLangCode;
  utterance.rate = rate;
  utterance.pitch = 1.0;
  utterance.volume = 1.0;
  
  const enhancedVoice = getEnhancedVoice();
  if (enhancedVoice) {
    utterance.voice = enhancedVoice;
    console.log("Selected voice:", enhancedVoice.name, enhancedVoice.lang);
  }
  
  utterance.onend = () => {
    console.log("Speech playback complete");
  };
  
  utterance.onerror = (error) => {
    console.error("Speech synthesis error:", error);
  };
  
  utterance.onstart = () => {
    console.log("Speech playback started with rate:", utterance.rate);
  };
  
  window.speechSynthesis.speak(utterance);
}, [testType, selectedLanguage, questionPlaybackRate, getEnhancedVoice]);

