// GitHubSettings.js
import React, { useState, useEffect } from 'react';
import './GitHubSettings.css';

const GitHubSettings = ({ onClose }) => {
  const [username, setUsername] = useState(localStorage.getItem('github_username') || '');
  const [token, setToken] = useState(localStorage.getItem('github_token') || '');
  const [repo, setRepo] = useState(localStorage.getItem('github_repo') || 'quiz-repository');
  const [branch, setBranch] = useState(localStorage.getItem('github_branch') || 'main');
  const [testStatus, setTestStatus] = useState('');
  const [isTesting, setIsTesting] = useState(false);

  // 설정 저장
  const saveSettings = () => {
    localStorage.setItem('github_username', username);
    localStorage.setItem('github_token', token);
    localStorage.setItem('github_repo', repo);
    localStorage.setItem('github_branch', branch);
    
    setTestStatus('설정이 저장되었습니다.');
  };

  // 연결 테스트
  const testConnection = async () => {
    setIsTesting(true);
    setTestStatus('GitHub API 연결 테스트 중...');
    
    try {
      const response = await fetch(`https://api.github.com/repos/${username}/${repo}`, {
        headers: {
          'Accept': 'application/vnd.github.v3+json',
          'Authorization': `token ${token}`
        }
      });
      
      if (response.ok) {
        setTestStatus('✅ 연결 성공! 저장소에 접근할 수 있습니다.');
      } else if (response.status === 404) {
        // 저장소가 없으면 생성 시도
        setTestStatus('저장소가 존재하지 않습니다. 생성을 시도합니다...');
        const createResult = await createRepository();
        if (createResult) {
          setTestStatus('✅ 저장소 생성 및 연결 성공!');
        }
      } else {
        const errorData = await response.json();
        setTestStatus(`❌ 연결 실패: ${response.status} ${errorData.message}`);
      }
    } catch (error) {
      setTestStatus(`❌ 연결 테스트 오류: ${error.message}`);
    } finally {
      setIsTesting(false);
    }
  };

  // 저장소 생성
  const createRepository = async () => {
    try {
      const response = await fetch('https://api.github.com/user/repos', {
        method: 'POST',
        headers: {
          'Accept': 'application/vnd.github.v3+json',
          'Authorization': `token ${token}`,
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({
          name: repo,
          description: 'GPT QUIZ 41 Repository - 언어 학습 퀴즈 데이터 저장소',
          private: false,
          auto_init: true
        })
      });
      
      if (response.ok) {
        // 초기 인덱스 파일 생성
        await createInitialFiles();
        return true;
      } else {
        const errorData = await response.json();
        setTestStatus(`❌ 저장소 생성 실패: ${errorData.message}`);
        return false;
      }
    } catch (error) {
      setTestStatus(`❌ 저장소 생성 오류: ${error.message}`);
      return false;
    }
  };

  // 초기 파일 생성
  const createInitialFiles = async () => {
    try {
      // 인덱스 파일 생성
      const indexContent = {
        quizzes: [],
        lastUpdated: new Date().toISOString()
      };
      
      await fetch(`https://api.github.com/repos/${username}/${repo}/contents/index.json`, {
        method: 'PUT',
        headers: {
          'Accept': 'application/vnd.github.v3+json',
          'Authorization': `token ${token}`,
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({
          message: 'Initialize index file',
          content: btoa(JSON.stringify(indexContent, null, 2)),
          branch
        })
      });
      
      // README 파일 생성
      const readmeContent = `# GPT QUIZ 41 Repository
      
이 저장소는 GPT QUIZ 41 애플리케이션의 언어 학습 퀴즈 데이터를 저장하는 곳입니다.

## 구조

- \`index.json\`: 모든 퀴즈 데이터의 메타데이터와 경로 정보
- \`quiz/{language}/{level}/{category}.json\`: 개별 퀴즈 데이터

## 라이센스

이 저장소의 모든 컨텐츠는 학습 목적으로 자유롭게 사용할 수 있습니다.
      `;
      
      await fetch(`https://api.github.com/repos/${username}/${repo}/contents/README.md`, {
        method: 'PUT',
        headers: {
          'Accept': 'application/vnd.github.v3+json',
          'Authorization': `token ${token}`,
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({
          message: 'Add README',
          content: btoa(readmeContent),
          branch
        })
      });
      
      return true;
    } catch (error) {
      console.error('초기 파일 생성 오류:', error);
      return false;
    }
  };

  return (
    <div className="github-settings-container">
      <h2>GitHub 저장소 연동 설정</h2>
      
      <div className="settings-description">
        <p>
          GitHub 저장소를 연동하면 생성된 퀴즈 데이터를 저장하고 공유할 수 있습니다.
          개인 액세스 토큰(PAT)을 생성하려면 <a href="https://github.com/settings/tokens" target="_blank" rel="noreferrer">GitHub Token Settings</a>를 방문하세요.
        </p>
      </div>
      
      <div className="settings-form">
        <div className="form-group">
          <label>GitHub 사용자명</label>
          <input 
            type="text" 
            value={username} 
            onChange={(e) => setUsername(e.target.value)}
            placeholder="GitHub 사용자명"
          />
        </div>
        
        <div className="form-group">
          <label>개인 액세스 토큰 (PAT)</label>
          <input 
            type="password" 
            value={token} 
            onChange={(e) => setToken(e.target.value)}
            placeholder="ghp_xxxxxxxxxxxxxxxx"
          />
          <p className="form-hint">토큰에는 'repo' 권한이 필요합니다.</p>
        </div>
        
        <div className="form-group">
          <label>저장소 이름</label>
          <input 
            type="text" 
            value={repo} 
            onChange={(e) => setRepo(e.target.value)}
            placeholder="quiz-repository"
          />
        </div>
        
        <div className="form-group">
          <label>브랜치 이름</label>
          <input 
            type="text" 
            value={branch} 
            onChange={(e) => setBranch(e.target.value)}
            placeholder="main"
          />
        </div>
        
        {testStatus && (
          <div className={`connection-status ${testStatus.includes('✅') ? 'success' : testStatus.includes('❌') ? 'error' : 'info'}`}>
            {testStatus}
          </div>
        )}
        
        <div className="settings-actions">
          <button onClick={saveSettings} className="save-button">
            설정 저장
          </button>
          <button 
            onClick={testConnection} 
            className="test-button"
            disabled={isTesting || !username || !token || !repo}
          >
            {isTesting ? '테스트 중...' : '연결 테스트'}
          </button>
          <button onClick={onClose} className="cancel-button">
            닫기
          </button>
        </div>
      </div>
    </div>
  );
};

export default GitHubSettings;