// GitHubService.js
const GITHUB_API_URL = 'https://api.github.com';
const DEFAULT_REPO = 'quiz-repository';
const DEFAULT_BRANCH = 'main';

// 저장소 설정 가져오기
const getRepoConfig = () => {
  return {
    owner: localStorage.getItem('github_username') || '',
    repo: localStorage.getItem('github_repo') || DEFAULT_REPO,
    token: localStorage.getItem('github_token') || '',
    branch: localStorage.getItem('github_branch') || DEFAULT_BRANCH
  };
};

// 파일 경로 생성
const getFilePath = (language, category, level) => {
  const sanitizedCategory = category.toLowerCase().replace(/\s+/g, '_');
  return `quiz/${language}/${level}/${sanitizedCategory}.json`;
};

// 인덱스 파일 경로
const INDEX_FILE_PATH = 'index.json';

// GitHub API 호출 함수
const callGitHubAPI = async (endpoint, method = 'GET', data = null) => {
  const { token } = getRepoConfig();
  
  if (!token) {
    throw new Error('GitHub 토큰이 설정되지 않았습니다. 설정에서 GitHub 연동을 완료해주세요.');
  }
  
  const options = {
    method,
    headers: {
      'Accept': 'application/vnd.github.v3+json',
      'Authorization': `token ${token}`,
      'Content-Type': 'application/json'
    }
  };
  
  if (data && (method === 'POST' || method === 'PUT')) {
    options.body = JSON.stringify(data);
  }
  
  const response = await fetch(`${GITHUB_API_URL}${endpoint}`, options);
  
  if (!response.ok) {
    const errorData = await response.json().catch(() => ({}));
    throw new Error(`GitHub API 요청 실패: ${response.status} ${response.statusText}, ${JSON.stringify(errorData)}`);
  }
  
  return response.json();
};

// 파일 존재 여부 확인
const checkFileExists = async (path) => {
  const { owner, repo, branch } = getRepoConfig();
  
  try {
    await callGitHubAPI(`/repos/${owner}/${repo}/contents/${path}?ref=${branch}`);
    return true;
  } catch (error) {
    if (error.message.includes('404')) {
      return false;
    }
    throw error;
  }
};

// 파일 내용 가져오기
const getFileContent = async (path) => {
  const { owner, repo, branch } = getRepoConfig();
  
  try {
    const response = await callGitHubAPI(`/repos/${owner}/${repo}/contents/${path}?ref=${branch}`);
    
    // Base64 디코딩
    const content = atob(response.content);
    return {
      content: JSON.parse(content),
      sha: response.sha
    };
  } catch (error) {
    if (error.message.includes('404')) {
      return { content: null, sha: null };
    }
    throw error;
  }
};

// 파일 생성 또는 업데이트
const createOrUpdateFile = async (path, content, message, sha = null) => {
  const { owner, repo, branch } = getRepoConfig();
  
  const data = {
    message,
    content: btoa(JSON.stringify(content, null, 2)), // Base64 인코딩
    branch
  };
  
  if (sha) {
    data.sha = sha;
  }
  
  return callGitHubAPI(`/repos/${owner}/${repo}/contents/${path}`, 'PUT', data);
};

// 인덱스 파일 업데이트
const updateIndex = async (quizData, language, category, level) => {
  try {
    // 인덱스 파일 로드
    const { content: indexData, sha } = await getFileContent(INDEX_FILE_PATH);
    
    // 인덱스 데이터 초기화
    const newIndexData = indexData || { quizzes: [] };
    
    // 퀴즈 메타데이터 추가
    const quizMeta = {
      id: Date.now().toString(),
      language,
      category,
      level,
      keywords: generateKeywords(quizData),
      path: getFilePath(language, category, level),
      createdAt: new Date().toISOString()
    };
    
    // 기존 인덱스에 없는 경우에만 추가
    const existingIndex = newIndexData.quizzes.findIndex(q => 
      q.language === language && 
      q.category === category && 
      q.level === level
    );
    
    if (existingIndex >= 0) {
      newIndexData.quizzes[existingIndex] = quizMeta;
    } else {
      newIndexData.quizzes.push(quizMeta);
    }
    
    // 인덱스 파일 업데이트
    await createOrUpdateFile(
      INDEX_FILE_PATH,
      newIndexData,
      `Update index with ${language} ${category} (${level})`,
      sha
    );
    
    return quizMeta;
  } catch (error) {
    console.error('인덱스 업데이트 오류:', error);
    throw error;
  }
};

// 키워드 생성
const generateKeywords = (quizData) => {
  const keywords = new Set();
  
  // 각 퀴즈 문제에서 키워드 추출
  if (quizData && quizData.quiz && Array.isArray(quizData.quiz)) {
    quizData.quiz.forEach(question => {
      // 문제에서 키워드 추출
      const questionWords = question.question.split(/\s+/).filter(word => word.length > 3);
      questionWords.forEach(word => keywords.add(word.toLowerCase()));
      
      // 정답에서 키워드 추출
      if (question.answer && typeof question.answer === 'string') {
        keywords.add(question.answer.toLowerCase());
      }
    });
  }
  
  return Array.from(keywords).slice(0, 10); // 최대 10개 키워드
};

// 퀴즈 데이터 저장
const saveQuizToGitHub = async (quizData, language, category, level) => {
  try {
    const filePath = getFilePath(language, category, level);
    
    // 파일 존재 여부 확인
    const fileExists = await checkFileExists(filePath);
    let sha = null;
    
    if (fileExists) {
      const fileData = await getFileContent(filePath);
      sha = fileData.sha;
    }
    
    // 메타데이터 추가
    quizData.metadata = {
      language,
      category,
      level,
      createdAt: new Date().toISOString()
    };
    
    // 파일 생성 또는 업데이트
    await createOrUpdateFile(
      filePath,
      quizData,
      `Update ${language} ${category} quiz (${level})`,
      sha
    );
    
    // 인덱스 업데이트
    const quizMeta = await updateIndex(quizData, language, category, level);
    
    // 로컬 캐시 업데이트
    updateLocalCache(filePath, quizData);
    
    return quizMeta;
  } catch (error) {
    console.error('GitHub에 퀴즈 저장 오류:', error);
    throw error;
  }
};

// 검색 기능
const searchQuizzes = async (searchParams = {}) => {
  try {
    const { language, category, level, keyword } = searchParams;
    
    // 인덱스 파일 로드
    const { content: indexData } = await getFileContent(INDEX_FILE_PATH);
    
    if (!indexData || !indexData.quizzes) {
      return [];
    }
    
    // 필터링
    let filteredQuizzes = indexData.quizzes;
    
    if (language) {
      filteredQuizzes = filteredQuizzes.filter(quiz => quiz.language === language);
    }
    
    if (category) {
      filteredQuizzes = filteredQuizzes.filter(quiz => quiz.category.toLowerCase().includes(category.toLowerCase()));
    }
    
    if (level) {
      filteredQuizzes = filteredQuizzes.filter(quiz => quiz.level === level);
    }
    
    if (keyword) {
      filteredQuizzes = filteredQuizzes.filter(quiz => 
        quiz.keywords.some(kw => kw.toLowerCase().includes(keyword.toLowerCase()))
      );
    }
    
    // 가장 최근 항목이 앞으로 오도록 정렬
    filteredQuizzes.sort((a, b) => new Date(b.createdAt) - new Date(a.createdAt));
    
    return filteredQuizzes;
  } catch (error) {
    console.error('퀴즈 검색 오류:', error);
    
    // 인덱스 파일이 없는 경우 빈 배열 반환
    if (error.message.includes('404')) {
      return [];
    }
    
    throw error;
  }
};

// 퀴즈 데이터 로드
const loadQuizFromGitHub = async (path) => {
  try {
    // 로컬 캐시 확인
    const cachedData = getFromLocalCache(path);
    if (cachedData) {
      return cachedData;
    }
    
    // GitHub에서 로드
    const { content: quizData } = await getFileContent(path);
    
    // 로컬 캐시 업데이트
    if (quizData) {
      updateLocalCache(path, quizData);
    }
    
    return quizData;
  } catch (error) {
    console.error('GitHub에서 퀴즈 로드 오류:', error);
    throw error;
  }
};

// 로컬 캐시 관리
const CACHE_PREFIX = 'github_quiz_cache_';
const CACHE_EXPIRY = 24 * 60 * 60 * 1000; // 24시간

const getFromLocalCache = (path) => {
  const cacheKey = `${CACHE_PREFIX}${path}`;
  const cachedItem = localStorage.getItem(cacheKey);
  
  if (cachedItem) {
    try {
      const { data, timestamp } = JSON.parse(cachedItem);
      
      // 캐시 만료 확인
      if (Date.now() - timestamp < CACHE_EXPIRY) {
        return data;
      }
    } catch (e) {
      // 캐시 파싱 오류 - 무시하고 진행
    }
  }
  
  return null;
};

const updateLocalCache = (path, data) => {
  const cacheKey = `${CACHE_PREFIX}${path}`;
  const cacheItem = {
    data,
    timestamp: Date.now()
  };
  
  try {
    localStorage.setItem(cacheKey, JSON.stringify(cacheItem));
  } catch (e) {
    // localStorage 용량 초과 시 - 가장 오래된 캐시 제거
    clearOldestCache();
    try {
      localStorage.setItem(cacheKey, JSON.stringify(cacheItem));
    } catch (e2) {
      console.error('캐시 저장 오류:', e2);
    }
  }
};

const clearOldestCache = () => {
  // localStorage에서 캐시 키만 필터링
  const cacheKeys = Object.keys(localStorage)
    .filter(key => key.startsWith(CACHE_PREFIX));
  
  if (cacheKeys.length === 0) return;
  
  // 가장 오래된 캐시 찾기
  let oldestKey = cacheKeys[0];
  let oldestTimestamp = Infinity;
  
  cacheKeys.forEach(key => {
    try {
      const { timestamp } = JSON.parse(localStorage.getItem(key));
      if (timestamp < oldestTimestamp) {
        oldestTimestamp = timestamp;
        oldestKey = key;
      }
    } catch (e) {
      // 파싱 오류 - 이 키를 제거 대상으로 설정
      oldestKey = key;
    }
  });
  
  // 가장 오래된 캐시 제거
  localStorage.removeItem(oldestKey);
};

// URL 공유 생성
const createShareURL = (quizMeta) => {
  const baseURL = window.location.origin + window.location.pathname;
  const params = new URLSearchParams();
  
  params.set('mode', 'quiz');
  params.set('path', quizMeta.path);
  
  return `${baseURL}?${params.toString()}`;
};

export {
  saveQuizToGitHub,
  loadQuizFromGitHub,
  searchQuizzes,
  createShareURL,
  getRepoConfig
};